import{_ as t,c as a,o as e,a4 as d}from"./chunks/framework.nQaBHiNx.js";const k=JSON.parse('{"title":"第十一章 XML 究竟是什么","description":"","frontmatter":{"permalink":"/basic/computer/how-the-computer-works/11.html"},"headers":[],"relativePath":"computer/book/how-the-computer-works/11-第十一章 XML 究竟是什么.md","filePath":"computer/book/how-the-computer-works/11-第十一章 XML 究竟是什么.md"}'),s={name:"computer/book/how-the-computer-works/11-第十一章 XML 究竟是什么.md"},r=d('<h1 id="第十一章-xml-究竟是什么" tabindex="-1">第十一章 XML 究竟是什么 <a class="header-anchor" href="#第十一章-xml-究竟是什么" aria-label="Permalink to &quot;第十一章 XML 究竟是什么&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">HTML 和 XML 的区别是什么？</p><p>HTML 是用于编写网页的标记语言。 XML 是用于定义任意标记语言的元语言。</p></div><div class="tip custom-block"><p class="custom-block-title">在处理 XML 文档的程序组件中，哪个成为了 W3C 的推荐标准？</p><p>DOM ( Document Object Model, 文档对象模型 )</p></div><h2 id="_11-1-xml-是标记语言" tabindex="-1">11.1 XML 是标记语言 <a class="header-anchor" href="#_11-1-xml-是标记语言" aria-label="Permalink to &quot;11.1 XML 是标记语言&quot;">​</a></h2><p>通常把通过添加标签为数据赋予意义的行为成为“标记”。为这种给数据赋予意义的行为定义规则的语言就是“标记语言”。 HTML 是用于编写网页的标记语言，更简单地说法就是 HTML 决定了可用于编写网页的标签。</p><h2 id="_11-2-xml-是可扩展的语言" tabindex="-1">11.2 XML 是可扩展的语言 <a class="header-anchor" href="#_11-2-xml-是可扩展的语言" aria-label="Permalink to &quot;11.2 XML 是可扩展的语言&quot;">​</a></h2><p>而 XML 本身不会限定标签的种类，允许使用者随心所欲的创建标签。这就是所谓的“可扩展”。</p><h2 id="_11-3-xml-是元语言" tabindex="-1">11.3 XML 是元语言 <a class="header-anchor" href="#_11-3-xml-是元语言" aria-label="Permalink to &quot;11.3 XML 是元语言&quot;">​</a></h2><h2 id="_11-4-xml-可以为信息赋予意义" tabindex="-1">11.4 XML 可以为信息赋予意义 <a class="header-anchor" href="#_11-4-xml-可以为信息赋予意义" aria-label="Permalink to &quot;11.4 XML 可以为信息赋予意义&quot;">​</a></h2><h2 id="_11-5-xml-是通用的数据交换格式" tabindex="-1">11.5 XML 是通用的数据交换格式 <a class="header-anchor" href="#_11-5-xml-是通用的数据交换格式" aria-label="Permalink to &quot;11.5 XML 是通用的数据交换格式&quot;">​</a></h2><h2 id="_11-6-可以为-xml-标签设定命名空间" tabindex="-1">11.6 可以为 XML 标签设定命名空间 <a class="header-anchor" href="#_11-6-可以为-xml-标签设定命名空间" aria-label="Permalink to &quot;11.6 可以为 XML 标签设定命名空间&quot;">​</a></h2><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">cat</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> xmlns</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://www.gausszhou.top/&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">cat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h2 id="_11-7-可以严格地定义-xml-的文档结构" tabindex="-1">11.7 可以严格地定义 XML 的文档结构 <a class="header-anchor" href="#_11-7-可以严格地定义-xml-的文档结构" aria-label="Permalink to &quot;11.7 可以严格地定义 XML 的文档结构&quot;">​</a></h2><h2 id="_11-8-用于解析-xml-的组件" tabindex="-1">11.8 用于解析 XML 的组件 <a class="header-anchor" href="#_11-8-用于解析-xml-的组件" aria-label="Permalink to &quot;11.8 用于解析 XML 的组件&quot;">​</a></h2><p>SAX (Simple API for XML)</p><h2 id="_11-9-xml-可用于各种各样的领域" tabindex="-1">11.9 XML 可用于各种各样的领域 <a class="header-anchor" href="#_11-9-xml-可用于各种各样的领域" aria-label="Permalink to &quot;11.9 XML 可用于各种各样的领域&quot;">​</a></h2><table><thead><tr><th>名称</th><th>用途</th><th>有关的企业或组织</th></tr></thead><tbody><tr><td>XSL</td><td>为 XML 中的信息提供显示格式</td><td>W3C</td></tr><tr><td><strong>MathML</strong></td><td>描述数学算式</td><td>W3C</td></tr><tr><td>SMIL</td><td>把多媒体数据嵌入到网页中</td><td>W3C</td></tr><tr><td>MML</td><td>描述电子病历</td><td>电子病历研究会</td></tr><tr><td><strong>SVG</strong></td><td>用向量表示图形数据</td><td>W3C</td></tr><tr><td>JepaX</td><td>表示电子书</td><td>日本电子出版协会等</td></tr><tr><td>WML</td><td>表示移动终端上的内容</td><td>WAP Forum</td></tr><tr><td>CHTML</td><td>表示手机上的内容</td><td>Acces 等 6 家公司</td></tr><tr><td>XHTML</td><td>用 XML 定义 HTML4.0</td><td>W3C</td></tr><tr><td><strong>SOAP</strong></td><td>实现分布式计算</td><td>W3C</td></tr></tbody></table>',17),i=[r];function l(o,h,n,c,p,m){return e(),a("div",null,i)}const u=t(s,[["render",l]]);export{k as __pageData,u as default};
